}

@Composable
private fun WorkoutReportScreen(results: List<ExerciseResult>, skipped: List<String>, onDone: () -> Unit) {
    var selectedFeedback by remember { mutableStateOf<String?>(null) }
    var isSubmitting by remember { mutableStateOf(false) }
    val context = LocalContext.current

    Column(Modifier.fillMaxSize().padding(16.dp).verticalScroll(rememberScrollState())) {
        Text("Done! ", style = MaterialTheme.typography.headlineLarge, fontWeight = FontWeight.Bold)
        Spacer(Modifier.height(8.dp))

        // ADDED: Confirmation banner (P0 UX Improvement)
        Card(
            modifier = Modifier.fillMaxWidth().padding(bottom = 16.dp),
            colors = CardDefaults.cardColors(
                containerColor = UppColors.Success.copy(alpha = 0.15f)
            )
        ) {
            Row(
                modifier = Modifier.padding(16.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text("‚úÖ", fontSize = 24.sp)
                Spacer(Modifier.width(12.dp))
                Column {
                    Text("Workout Saved", fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onSurface)
                    Text("Saved to history ‚ÄĘ +XP ‚ÄĘ Streak updated", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurfaceVariant)
                }
            }
        }

        val totalKcal = results.sumOf { it.caloriesKcal }
        Text("Total: $totalKcal kcal burned", style = MaterialTheme.typography.titleMedium, color = MaterialTheme.colorScheme.primary)
        Spacer(Modifier.height(12.dp))
        results.forEach { Text("‚ÄĘ ${it.name}: ${it.caloriesKcal} kcal") }

        Spacer(Modifier.height(24.dp))
        Text("How was the workout?", style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.SemiBold)
        Spacer(Modifier.height(8.dp))
        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
            listOf("Too Short", "Just Right", "Too Long").forEach { feedback ->
                val isSelected = selectedFeedback == feedback
                Button(
                    onClick = {
                        selectedFeedback = feedback
                        val adjustment = when (feedback) {
                            "Too Short" -> 1
                            "Too Long" -> -1
                            else -> 0
                        }
                        AlgorithmPreferences.saveGlobalFeedback(context.getAlgoSettings(), adjustment)
                        AppToast.showSuccess(context, "Thanks! Adjusting next workout...")
                    },
                    colors = ButtonDefaults.buttonColors(
                        containerColor = if (isSelected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.surfaceVariant,
                        contentColor = if (isSelected) MaterialTheme.colorScheme.onPrimary else MaterialTheme.colorScheme.onSurfaceVariant
                    )
                ) {
                    Text(feedback)
                }
            }
        }

        Spacer(Modifier.weight(1f))
        Button(
            onClick = {
                if (!isSubmitting) {
                    isSubmitting = true
                    onDone()
                }
            },
            modifier = Modifier.fillMaxWidth().height(56.dp),
            enabled = !isSubmitting
        ) {
            if (isSubmitting) {
                CircularProgressIndicator(modifier = Modifier.size(24.dp), color = MaterialTheme.colorScheme.onPrimary)
            } else {
                Text("Finish")
            }
        }
    }
}

@Composable
private fun WorkoutCelebrationScreen(
    isExtra: Boolean,
    nextDayPreview: String? = null,
    planDay: Int = 0,         // ‚úÖ Prejeto iz BodyModuleHomeViewModel (Firestore SSOT, ne bm_prefs)
    streakDays: Int = 0,      // ‚úÖ Firestore SSOT prek BodyModuleHomeViewModel.ui.streakDays
    onContinue: () -> Unit
) {
    val scale = remember { Animatable(0f) }
    val streakScale = remember { Animatable(0f) }
    val confettiAlpha = remember { Animatable(0f) }

    LaunchedEffect(Unit) {
        scale.animateTo(1.2f, tween(400, easing = FastOutSlowInEasing))
        scale.animateTo(0.9f, tween(150))
        scale.animateTo(1.0f, tween(150))
        delay(300)
        confettiAlpha.animateTo(1f, tween(500))
        streakScale.animateTo(1.3f, tween(400, easing = FastOutSlowInEasing))
        streakScale.animateTo(1.0f, tween(200))
    }

    val context = LocalContext.current  // ‚Üź potrebno za HapticFeedback
    // ‚úÖ streakDays prejmemo kot parameter iz BodyModuleHomeViewModel (Firestore SSOT)
    val currentStreak = streakDays
    // planDay prejmemo kot parameter iz BodyModuleHomeViewModel (Firestore SSOT)

    // Animate from (current - 1) to (current)
    val startStreak = (currentStreak - 1).coerceAtLeast(0)
    val targetStreak = currentStreak
    val streakAnim = remember { Animatable(startStreak.toFloat()) }

    // Firework animation state for the moment streak changes
    val streakBump = remember { Animatable(1f) }

    LaunchedEffect(Unit) {
        delay(1000) // Wait for initial popup to settle
        streakAnim.animateTo(
            targetValue = targetStreak.toFloat(),
            animationSpec = tween(durationMillis = 1000, easing = FastOutSlowInEasing)
        )
    }

    // Haptics & Bump logic
    LaunchedEffect(streakAnim) {
        var lastVal = startStreak
        snapshotFlow { streakAnim.value.toInt() }
            .collectLatest { current ->
                if (current != lastVal) {
                    lastVal = current
                    // Haptic feedback
                    HapticFeedback.performHapticFeedback(
                        context,
                        HapticFeedback.FeedbackType.HEAVY_CLICK
                    )
                    // Visual bump
                    streakBump.snapTo(1.5f)
                    streakBump.animateTo(1f, tween(300, easing = FastOutSlowInEasing))
                }
            }
    }

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(MaterialTheme.colorScheme.background)
            .windowInsetsPadding(WindowInsets.systemBars),
        contentAlignment = Alignment.Center
    ) {
        // Confetti for regular workout
        if (!isExtra) {
            val infiniteTransition = rememberInfiniteTransition(label = "confetti")
            val confettiOffset by infiniteTransition.animateFloat(
                initialValue = 0f, targetValue = 1f,
                animationSpec = infiniteRepeatable(
                    animation = tween(2000),
                    repeatMode = RepeatMode.Restart
                ), label = "confettiOff"
            )
            val confettiColors = listOf(MaterialTheme.colorScheme.secondary, MaterialTheme.colorScheme.primary, UppColors.Success, MaterialTheme.colorScheme.tertiary, UppColors.Blue)
            repeat(30) { i -> // Increased confetti count
                val xPos = (i * 83 % 100) / 100f
                val startY = ((i * 47 + confettiOffset * 100) % 110) / 100f
                Box(modifier = Modifier.fillMaxSize().graphicsLayer(alpha = confettiAlpha.value)) {
                    Box(
                        modifier = Modifier
                            .absoluteOffset(x = (xPos * 400 - 20).dp, y = (startY * 900 - 50).dp)
                            .size(if(i % 3 == 0) 10.dp else 6.dp)
                            .background(confettiColors[i % confettiColors.size], CircleShape)
                    )
                }
            }
        }

        Column(
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center,
            modifier = Modifier.padding(32.dp)
        ) {
            Text(
                text = if (isExtra) "" else "",
                fontSize = 80.sp,
                modifier = Modifier.graphicsLayer(scaleX = scale.value, scaleY = scale.value)
            )
            Spacer(Modifier.height(24.dp))

            if (isExtra) {
                Text(
                    "Extra Workout Done!",
                    fontSize = 28.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onBackground,
                    textAlign = TextAlign.Center,
                    modifier = Modifier.graphicsLayer(scaleX = streakScale.value, scaleY = streakScale.value)
                )
                Spacer(Modifier.height(8.dp))
                Text("You went beyond today's plan! ", fontSize = 16.sp, color = MaterialTheme.colorScheme.onSurfaceVariant, textAlign = TextAlign.Center)
                Spacer(Modifier.height(24.dp))
                val armScale = remember { Animatable(0.8f) }
                LaunchedEffect(Unit) {
                    delay(600)
                    while (true) {
                        armScale.animateTo(1.15f, tween(700))
                        armScale.animateTo(0.95f, tween(500))
                    }
                }
                Text("‚Üí", fontSize = 48.sp, modifier = Modifier.graphicsLayer(scaleX = armScale.value, scaleY = armScale.value))
            } else {
                Text("Workout Complete!", fontSize = 28.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onBackground, textAlign = TextAlign.Center)
                Spacer(Modifier.height(20.dp))
                Card(
                    shape = androidx.compose.foundation.shape.RoundedCornerShape(20.dp),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant),
                    modifier = Modifier.fillMaxWidth().graphicsLayer(scaleX = streakScale.value, scaleY = streakScale.value)
                ) {
                    Row(
                        modifier = Modifier.padding(20.dp).fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceEvenly,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            Text("", fontSize = 36.sp)

                            // Animated streak number
                            Text(
                                text = "${streakAnim.value.toInt()}",
                                fontSize = 32.sp,
                                fontWeight = FontWeight.Bold,
                                color = MaterialTheme.colorScheme.secondary,
                                modifier = Modifier.graphicsLayer {
                                    scaleX = streakBump.value
                                    scaleY = streakBump.value
                                }
                            )
                            Text("Day streak", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurfaceVariant)
                        }
                        Box(modifier = Modifier.height(60.dp).width(1.dp).background(MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha=0.3f)))
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            // NO CALENDAR ICON - Just text
                            Spacer(Modifier.height(4.dp))
                            Text("Day $planDay", fontSize = 24.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.primary)
                            Text("of your plan", fontSize = 13.sp, color = MaterialTheme.colorScheme.onSurfaceVariant)
                        }
                    }
                }
                Spacer(Modifier.height(12.dp))
                val motivations = listOf("Keep it up! ", "You're unstoppable! ‚ö°", "One day at a time! ", "Consistency is key! ", "You're crushing it! ")
                Text(motivations[targetStreak % motivations.size], fontSize = 16.sp, color = MaterialTheme.colorScheme.primary, textAlign = TextAlign.Center, fontWeight = FontWeight.Medium)

                // ADDED: P1 Next Day Preview
                if (!isExtra && nextDayPreview != null) {
                    Spacer(Modifier.height(24.dp))
                    Surface(
                        color = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f),
                        shape = androidx.compose.foundation.shape.RoundedCornerShape(12.dp)
                    ) {
                        Text(
                            text = nextDayPreview,
                            fontSize = 14.sp,
                            fontWeight = FontWeight.SemiBold,
                            color = MaterialTheme.colorScheme.onSurfaceVariant,
                            modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp)
                        )
                    }
                }
            }

            Spacer(Modifier.height(40.dp))
            Button(
                onClick = onContinue,
                modifier = Modifier.fillMaxWidth().height(56.dp),
                colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.primary),
                shape = androidx.compose.foundation.shape.RoundedCornerShape(28.dp)
            ) {
                Text("Continue", fontSize = 18.sp, fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.onPrimary)
            }
        }
    }
}

private fun Context.getAlgoSettings() =
    SharedPreferencesSettings(this.getSharedPreferences("algorithm_prefs", Context.MODE_PRIVATE))

package com.example.myapplication.viewmodels
import androidx.lifecycle.ViewModel import androidx.lifecycle.viewModelScope import com.example.myapplication.R import com.example.myapplication.data.UserProfile import com.example.myapplication.domain.model.BodyField import com.example.myapplication.domain.model.BodyGoldenRatioResult import com.example.myapplication.domain.model.PlanResult import com.example.myapplication.domain.model.UserDayStatus import com.example.myapplication.domain.gamification.ManageGamificationUseCase import com.example.myapplication.domain.gamification.WorkoutCompletionResult import com.example.myapplication.domain.auth.AuthStateRepository import com.example.myapplication.domain.profile.UserProfileRepository import com.example.myapplication.domain.model.BodyMeasurementEntry import com.example.myapplication.domain.repository.BodyMeasurementsRepository import com.example.myapplication.domain.usecase.CalculateBodyGoldenRatioUseCase import com.example.myapplication.domain.usecase.GetBodyMetricsUseCase import com.example.myapplication.domain.usecase.SaveBodyMeasurementsUseCase import com.example.myapplication.domain.usecase.SwapPlanDaysUseCase import com.example.myapplication.domain.usecase.UpdateBodyMetricsUseCase import com.example.myapplication.domain.usecase.ValidationResult import kotlinx.coroutines.Job import kotlinx.coroutines.channels.Channel import kotlinx.coroutines.flow.MutableSharedFlow import kotlinx.coroutines.flow.MutableStateFlow import kotlinx.coroutines.flow.SharedFlow import kotlinx.coroutines.flow.SharingStarted import kotlinx.coroutines.flow.StateFlow import kotlinx.coroutines.flow.asSharedFlow import kotlinx.coroutines.flow.asStateFlow import kotlinx.coroutines.flow.combine import kotlinx.coroutines.flow.flatMapLatest import kotlinx.coroutines.flow.flowOf import kotlinx.coroutines.flow.receiveAsFlow import kotlinx.coroutines.flow.stateIn import kotlinx.coroutines.launch
/** * Faza 30.9 ‚ÄĒ Enkratni UI dogodki za BodyModul. * * Razlika od StateFlow: * StateFlow = trajno stanje (kateri zaslon je odprt, ali nalagamo‚Ä¶) * Channel = enkratni dogodek (prikaŇĺi Snackbar, navigiraj, zapri dialog) * * Ne smeŇ° shranjevati teh vrednosti v StateFlow ‚ÄĒ Snackbar bi se ob rotaciji zaslona * prikazal znova. Channel zagotavlja natanko en sprejem. */ sealed interface BodyUiEvent { /** Meritve so bile uspeŇ°no shranjene v Firestore. */ data object SaveSuccess : BodyUiEvent /** Napaka med shranjevanjem ‚ÄĒ prikaŇĺi Snackbar z [message]. */ data class Error(val message: String) : BodyUiEvent }
/** * Faza 31.1 ‚ÄĒ Enoten UI state za Golden Ratio sekcijo. * Faza 31.3 ‚ÄĒ inputErrorRes: Int? ‚Üí invalidFields: Set<BodyField> za per-field natanńćnost. * * Faza 31.6 ‚ÄĒ Dead code odstranjen: bodyProfile je zdaj private, measurementsHistory izbrisan. * * NadomeŇ°ńća tri razprŇ°ene StateFlow-e (zdaj odstranjene/private): * bodyProfile (private) ‚Üí pokrit z Loading/Success * goldenRatioResults: StateFlow<Result?> ‚Üí Success.data * isSaving: StateFlow<Boolean> ‚Üí Success.isSaving * * Prednosti: * ‚ÄĘ Atomarni prehodi ‚ÄĒ UI nikoli ne vidi nedosledne kombinacije vrednosti * ‚ÄĘ Loading stanje prepreńćuje vizualno utripanje ("flash of empty content") * ‚ÄĘ invalidFields: UI obarva SAMO polja, ki so dejansko zunaj meja */ sealed interface GoldenRatioUiState { /** Profil se nalaga iz Firestore ‚ÄĒ pokaŇĺi CircularProgressIndicator. */ data object Loading : GoldenRatioUiState
/** * Profil naloŇĺen ‚ÄĒ pokaŇĺi celotni vmesnik z vnosi. * @param profileHeight ViŇ°ina iz profila (za prikaz in izrańćun pas/viŇ°ina razmerja) * @param shoulderInput Faza 31.4 ‚ÄĒ surovi vnos za ramena (String, ne Double) * @param waistInput Faza 31.4 ‚ÄĒ surovi vnos za pas * @param hipInput Faza 31.4 ‚ÄĒ surovi vnos za boke (prazno = ni vnosu) * @param data Rezultat izrańćuna; null dokler vnos ni veljaven/popoln * @param isSaving true med Firestore batch write ‚ÄĒ gumb onemogońćen * @param invalidFields Set polj, ki so zunaj bioloŇ°kih meja (30‚Äď250 cm). * @param isInputComplete Faza 31.5 ‚ÄĒ true ko so vsa 4 polja (ramena, pas, boki, viŇ°ina) * uspeŇ°no parsana v vrednosti > 0.0. Ko false + data==null + ni napak, * UI prikaŇĺe nevtralen napotek za vnos. */ data class Success( val profileHeight: Double?, val shoulderInput: String = "", val waistInput: String = "", val hipInput: String = "", val data: BodyGoldenRatioResult?, val isSaving: Boolean = false, val invalidFields: Set<BodyField> = emptySet(), val isInputComplete: Boolean = false ) : GoldenRatioUiState
/** * Napaka pri inicializaciji zaslona (npr. izpad Firestore med nalaganjem profila). * NI namenjen validacijskim napakam vnosa ‚ÄĒ za to se uporablja [Success.invalidFields]. * @param messageRes ID string resursa (R.string.*) ‚ÄĒ lokalizabilen, brez Context v VM */ data class Error(val messageRes: Int) : GoldenRatioUiState }
/** * Faza 30.1 ‚ÄĒ Vhodni podatki za telesni Zlati Rez. * shoulderCm/waistCm = 0.0 pomeni: ni vnosa ‚Üí goldenRatioResults = null. */ data class BodyMeasurementsInput( val shoulderCm: Double = 0.0, val waistCm: Double = 0.0, val hipCm: Double = 0.0, val heightCm: Double = 0.0 // fallback, ńće profil nima viŇ°ine )
/** * Faza 31.4 ‚ÄĒ Surovi tekstovni vnosi za telesne mere. * Nahajajo se v ViewModel StateFlow (ne v lokalni Compose state!) ‚Üí * preŇĺivijo UI state tranzicije (Loading ‚Üí Success itd.) brez izgube. */ data class BodyMeasurementsInputText( val shoulder: String = "", val waist: String = "", val hip: String = "" )
data class Challenge( val id: String, val title: String, val description: String, val xpReward: Int = 100, val accepted: Boolean = false, val completed: Boolean = false, val iconRes: Int? = null )
/** * UI stanje za Body Home zaslon. * * Faza 21: todayStatus je zdaj tipsko-varni [UserDayStatus] namesto String. */ data class BodyHomeUiState( val streakDays: Int = 0, val streakFreezes: Int = 0, val weeklyDone: Int = 0, val weeklyTarget: Int = 3, val planDay: Int = 1, val totalWorkoutsCompleted: Int = 0, val workoutsToday: Int = 0, val isWorkoutDoneToday: Boolean = false, val dailyKcal: Int = 0, val showCompletionAnimation: Boolean = false, val todayIsRest: Boolean = false, val outdoorSuggestion: String? = null, val errorMessage: String? = null, val isLoading: Boolean = false, /** Tipsko-varni status danaŇ°njega dne ‚ÄĒ nadomeŇ°ńća String "WORKOUT_DONE" itd. */ val todayStatus: UserDayStatus = UserDayStatus.WORKOUT_PENDING, val challenges: List<Challenge> = listOf( Challenge("c1", "30 days sixpack", "Get a sixpack in 30 days. Perform core exercises daily.", 500), Challenge("c2", "30 days pushups", "Improve your pushups in 30 days. Do 50 pushups/day.", 300), Challenge("c3", "Mobility week", "Increase your ROM in 7 days. Stretch every morning.", 150) ) )
sealed class BodyHomeIntent { data class LoadMetrics(val email: String, val plan: PlanResult? = null) : BodyHomeIntent() object CompleteRestDay : BodyHomeIntent() object HideCompletionAnimation : BodyHomeIntent() data class AcceptChallenge(val id: String) : BodyHomeIntent() data class CompleteChallenge(val id: String) : BodyHomeIntent() data class SwapDays(val currentPlan: PlanResult, val dayA: Int, val dayB: Int, val onResult: (PlanResult) -> Unit) : BodyHomeIntent() data class CompleteWorkoutSession( val email: String, val isExtraWorkout: Boolean = false, val totalKcal: Int = 0, val totalTimeMin: Double = 0.0, val exerciseResults: List<Map<String, Any>> = emptyList(), val focusAreas: List<String> = emptyList(), val onCompletion: (WorkoutCompletionResult?) -> Unit = {} ) : BodyHomeIntent() }
data class StreakUpdateEvent(val newStreak: Int, val isRestDay: Boolean = false)
/** * Faza 30.2 ‚ÄĒ BodyModuleHomeViewModel brez kakrŇ°nih koli Firebase SDK klicev. * Faza 30.6 ‚ÄĒ Dodan BodyMeasurementsRepository za zgodovino meritev. * * Auth stanje pride reaktivno prek [AuthStateRepository] vmesnika. * Profil se avtomatińćno osveŇĺuje ob spremembi prijave (flatMapLatest). */ class BodyModuleHomeViewModel( private val getBodyMetrics: GetBodyMetricsUseCase, private val updateBodyMetrics: UpdateBodyMetricsUseCase, private val swapPlanDays: SwapPlanDaysUseCase, private val gamificationUseCase: ManageGamificationUseCase? = null, private val userProfileRepository: UserProfileRepository, private val authStateRepository: AuthStateRepository, // Faza 30.6: Repozitorij za shranjevanje in opazovanje zgodovine meritev private val bodyMeasurementsRepository: BodyMeasurementsRepository ) : ViewModel() {
// ‚ĒÄ‚ĒÄ Faza 30.1 ‚ÄĒ Domain Use Case za telesni Zlati Rez ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ private val calculateBodyGoldenRatio = CalculateBodyGoldenRatioUseCase()
// ‚ĒÄ‚ĒÄ Faza 30.6 ‚ÄĒ Use Case za shranjevanje meritev (DI prek konstruktorja) ‚ĒÄ‚ĒÄ private val saveMeasurementsUseCase = SaveBodyMeasurementsUseCase(bodyMeasurementsRepository)
// ‚ĒÄ‚ĒÄ Faza 30.2 ‚ÄĒ Reaktivni profil brez Firebase v VM ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ /** * flatMapLatest: ob vsaki spremembi stanja prijave (login/logout) se * avtomatińćno zamenja na pravi profil ali flowOf(null). * PreŇĺivi rotacijo zaslona ‚ÄĒ ViewModel ostane Ňĺiv med config change. * * Faza 31.6 ‚ÄĒ private: profil se ne izpostavlja UI neposredno. * Javni dostop poteka izkljuńćno prek goldenRatioUiState. */ private val bodyProfile: StateFlow<UserProfile?> = authStateRepository.observeCurrentUserEmail() .flatMapLatest { email -> if (email != null) userProfileRepository.observeUserProfile(email) else flowOf(null) } .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), null)
// ‚ĒÄ‚ĒÄ Faza 30.1 ‚Üí Faza 31.4 ‚ÄĒ Vhodni teksti (String, ne Double) v ViewModel ‚ĒÄ /** * Faza 31.4 ‚ÄĒ Surovi vnosi so StateFlow v ViewModel (ne lokalni rememberSaveable). * PreŇĺivijo vsak UI state transition (Loading ‚ÜĒ Success) brez izgube vrednosti. */ private val _inputText = MutableStateFlow(BodyMeasurementsInputText())
// ‚ĒÄ‚ĒÄ Faza 30.8 ‚ÄĒ Stanje shranjevanja (interno ‚ÄĒ javno prek goldenRatioUiState) ‚ĒÄ private val _isSaving = MutableStateFlow(false)
/** * Faza 31.1 ‚ÄĒ ENOTEN UI STATE za Golden Ratio sekcijo. * Faza 31.4 ‚ÄĒ Input strings so del Success stanja ‚Üí UI vidi tońćno kar je vtipkal. * * Kombinira 3 vire (bodyProfile + _inputText + _isSaving) v en atomaren tok. * Parsing string‚ÜíDouble se dogaja TUKAJ ‚ÄĒ UI ostane ńćist (ne operira s float-i). */ val goldenRatioUiState: StateFlow<GoldenRatioUiState> = combine( bodyProfile, _inputText, _isSaving ) { profile, texts, saving -> // Faza 31.5 ‚ÄĒ Locale-safe parsing: zamenjaj vejico s piko (slovenska tipkovnica) // "75,5" ‚Üí "75.5" ‚Üí 75.5 | "" ‚Üí 0.0 | "abc" ‚Üí 0.0 val shoulderCm = texts.shoulder.replace(',', '.').toDoubleOrNull() ?: 0.0 val waistCm = texts.waist.replace(',', '.').toDoubleOrNull() ?: 0.0 val hipCm = texts.hip.replace(',', '.').toDoubleOrNull() ?: 0.0 val heightCm = profile?.height ?: 0.0
// Faza 31.5 ‚ÄĒ Zastavica za POPOLN vnos: vsa 4 polja > 0 // false ‚Üí UI prikaŇĺe nevtralen napotek; true + data!=null ‚Üí prikaŇĺi rezultat val isInputComplete = shoulderCm > 0.0 && waistCm > 0.0 && hipCm > 0.0 && heightCm > 0.0
when { profile == null -> GoldenRatioUiState.Loading else -> { // Klińći UseCase samo ko sta obe obvezni vrednosti vneseni if (shoulderCm > 0.0 && waistCm > 0.0) { when (val validation = calculateBodyGoldenRatio( shoulderCm = shoulderCm, waistCm = waistCm, hipCm = hipCm, heightCm = heightCm, isMale = profile.gender?.equals("Male", ignoreCase = true) ?: true )) { is ValidationResult.Success -> GoldenRatioUiState.Success( profileHeight = profile.height, shoulderInput = texts.shoulder, waistInput = texts.waist, hipInput = texts.hip, data = validation.data, isSaving = saving, invalidFields = emptySet(), isInputComplete = isInputComplete ) is ValidationResult.Invalid -> { android.util.Log.d( "BodyModuleHomeVM", "Per-field napaka: ${validation.invalidFields}" ) GoldenRatioUiState.Success( profileHeight = profile.height, shoulderInput = texts.shoulder, waistInput = texts.waist, hipInput = texts.hip, data = null, isSaving = saving, invalidFields = validation.invalidFields, isInputComplete = isInputComplete ) } } } else { // Polja prazna ali nepopolna ‚ÄĒ ńćisto stanje GoldenRatioUiState.Success( profileHeight = profile.height, shoulderInput = texts.shoulder, waistInput = texts.waist, hipInput = texts.hip, data = null, isSaving = saving, invalidFields = emptySet(), isInputComplete = isInputComplete ) } } } }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), GoldenRatioUiState.Loading)
/** * Faza 31.4 ‚ÄĒ Posodobi surove vnosne tekste (iz UI TextField). * Parsing string‚ÜíDouble se izvaja v combine, ne tukaj. */ fun updateInputText(shoulder: String, waist: String, hip: String) { _inputText.value = BodyMeasurementsInputText(shoulder, waist, hip) }
/** Faza 30.1 klińće UI ko vnese meritve ‚ÄĒ obdrŇĺano za morebitne klice od drugod. */ fun updateBodyMeasurements( shoulderCm: Double, waistCm: Double, hipCm: Double = 0.0, heightCm: Double = 0.0 ) { // Delegiraj na updateInputText ‚ÄĒ pretvori nazaj v string za konsistentnost _inputText.value = BodyMeasurementsInputText( shoulder = if (shoulderCm > 0) shoulderCm.toString() else "", waist = if (waistCm > 0) waistCm.toString() else "", hip = if (hipCm > 0) hipCm.toString() else "" ) }
// ‚ĒÄ‚ĒÄ Faza 30.9 ‚ÄĒ Enkratni UI dogodki (Channel = natanko en sprejem) ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ /** * Channel<BodyUiEvent>: poŇ°iljamo enkratne dogodke (Snackbar, navigacija‚Ä¶). * receiveAsFlow() v UI posluŇ°a z LaunchedEffect. * * Zakaj Channel in ne SharedFlow: * SharedFlow (replay=0) bi izgubil dogodek, ńće UI ni Ň°e narońćen. * Channel.BUFFERED ohrani sporońćilo dokler ga UI ne prebere. */ private val _uiEvent = Channel<BodyUiEvent>(Channel.BUFFERED) val uiEvents = _uiEvent.receiveAsFlow()
/** * Faza 30.6 ‚ÄĒ Shrani meritve v Firestore (batch write): * a) Posodobi profil z aktualnimi vrednostmi * b) Doda vnos v measurements_history (za grafe) * * Faza 30.8 ‚ÄĒ isSaving guard: klik na gumb med shranjevanjem se v celoti ignorira. * Faza 30.9 ‚ÄĒ napake se poŇ°ljejo kot BodyUiEvent.Error na Channel (‚Üí Snackbar v UI). * * Klic chain: UI ‚Üí VM ‚Üí SaveBodyMeasurementsUseCase ‚Üí BodyMeasurementsRepository ‚Üí Firestore */ fun saveBodyMeasurements( shoulderCm: Double, waistCm: Double, hipCm: Double = 0.0, heightCm: Double = 0.0 ) { // Dvojni klik ‚Üí prezri, ńće shranjevanje Ňĺe teńće if (_isSaving.value) return viewModelScope.launch { _isSaving.value = true try { val result = saveMeasurementsUseCase(shoulderCm, waistCm, hipCm, heightCm) result.onSuccess { android.util.Log.d("BodyModuleHomeVM", "‚úÖ Meritve shranjene v zgodovino") _uiEvent.send(BodyUiEvent.SaveSuccess) } result.onFailure { e -> android.util.Log.e("BodyModuleHomeVM", "‚ĚĆ Napaka pri shranjevanju meritev: ${e.message}") _uiEvent.send(BodyUiEvent.Error("Shranjevanje ni uspelo. Preverite povezavo.")) } } finally { // Vedno osvobodi, tudi ob nenapovedani izjemi _isSaving.value = false } } }
// ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ
private val _ui = MutableStateFlow(BodyHomeUiState()) val ui: StateFlow<BodyHomeUiState> = _ui.asStateFlow()
private val _streakUpdatedEvent = MutableSharedFlow<StreakUpdateEvent>(extraBufferCapacity = 1) val streakUpdatedEvent: SharedFlow<StreakUpdateEvent> = _streakUpdatedEvent.asSharedFlow()
/** * Faza 23: Job tracking za LoadMetrics ‚ÄĒ vsak klic cancela prejŇ°njega. * Prepreńćuje race condition med vzporednimi Firestore branii. */ private var loadMetricsJob: Job? = null
fun handleIntent(intent: BodyHomeIntent) { when (intent) { is BodyHomeIntent.LoadMetrics -> { // Cancela morebitni prejŇ°nji LoadMetrics ‚ÄĒ prepreńći dvojno branje loadMetricsJob?.cancel() loadMetricsJob = viewModelScope.launch { _ui.value = _ui.value.copy(isLoading = true, errorMessage = null) try { getBodyMetrics.invoke(intent.email).collect { metrics -> if (metrics.isLoading) return@collect val todayIsRest = intent.plan?.weeks ?.flatMap { it.days } ?.firstOrNull { it.dayNumber == metrics.planDay } ?.isRestDay ?: false
_ui.value = _ui.value.copy( streakDays = metrics.streakDays, streakFreezes = metrics.streakFreezes, weeklyDone = metrics.weeklyDone, weeklyTarget = metrics.weeklyTarget, planDay = metrics.planDay, totalWorkoutsCompleted = metrics.totalWorkoutsCompleted, isWorkoutDoneToday = metrics.isWorkoutDoneToday, dailyKcal = metrics.dailyKcal, todayIsRest = todayIsRest, todayStatus = metrics.todayStatus, isLoading = false, errorMessage = metrics.errorMessage ) } } catch (e: Exception) { _ui.value = _ui.value.copy(errorMessage = e.message, isLoading = false) } } }
is BodyHomeIntent.CompleteRestDay -> { if (gamificationUseCase == null) { android.util.Log.w("BodyModuleHomeVM", "gamificationUseCase ni nastavljen ‚ÄĒ preskońćim CompleteRestDay") return } viewModelScope.launch { _ui.value = _ui.value.copy(isLoading = true) try { val newStreak = gamificationUseCase.restDayInitiated() _ui.value = _ui.value.copy( isWorkoutDoneToday = true, streakDays = newStreak, todayStatus = UserDayStatus.REST_DAY_DONE, isLoading = false ) _streakUpdatedEvent.tryEmit(StreakUpdateEvent(newStreak = newStreak, isRestDay = true)) } catch (e: Exception) { _ui.value = _ui.value.copy(isLoading = false, errorMessage = e.message) } } }
is BodyHomeIntent.HideCompletionAnimation -> _ui.value = _ui.value.copy(showCompletionAnimation = false)
is BodyHomeIntent.AcceptChallenge -> { /* lokalni state */ } is BodyHomeIntent.CompleteChallenge -> { /* lokalni state */ }
is BodyHomeIntent.SwapDays -> { // Faza 30.4: ViewModel klińće SAMO SwapPlanDaysUseCase ‚ÄĒ ne PlanDataStore. // Klic chain: VM ‚Üí UseCase (validacija + lokalni model) ‚Üí Repository ‚Üí DataStore viewModelScope.launch { _ui.value = _ui.value.copy(isLoading = true, errorMessage = null) val lockedDay = if (_ui.value.isWorkoutDoneToday) _ui.value.planDay else null val res = swapPlanDays.invoke(intent.currentPlan, intent.dayA, intent.dayB, lockedDay) _ui.value = _ui.value.copy(isLoading = false) res.onSuccess { updatedPlan -> // Use case vrne posodobljeni model Ň°ele po uspeŇ°ni Firestore transakciji intent.onResult(updatedPlan) } res.onFailure { e -> _ui.value = _ui.value.copy(errorMessage = e.message) } } }
is BodyHomeIntent.CompleteWorkoutSession -> { viewModelScope.launch { _ui.value = _ui.value.copy(isLoading = true, errorMessage = null) val isRestDay = _ui.value.todayIsRest val isExtra = intent.isExtraWorkout val oldPlanDay = _ui.value.planDay val oldWeeklyDone = _ui.value.weeklyDone
val result = updateBodyMetrics.invoke( email = intent.email, totalKcal = intent.totalKcal, totalTimeMin = intent.totalTimeMin, exercisesCount = intent.exerciseResults.size, planDay = oldPlanDay, isExtra = isExtra, exerciseResults = intent.exerciseResults, focusAreas = intent.focusAreas, isRestDay = isRestDay )
result.onSuccess { completionResult -> // Faza 23: Optimistińćni update iz WorkoutCompletionResult ‚ÄĒ brez dodatnega Firestore read-a. // moveToNextDay() je atomarno Ňĺe zapisal vse podatke; streak + planDay sta znana. val todayStatus = when { isRestDay && isExtra -> UserDayStatus.REST_WORKOUT_DONE else -> UserDayStatus.WORKOUT_DONE } // Faza 31.6 avdit: moveToNextDay() vrne -1 ob Firestore napaki in 0 ob // de-dup preskohu. Oba primera filtered z takeIf { it > 0 }. // Fallback OHRANI STAR STREAK (ne poveńća) ‚ÄĒ UI ne sme prikazovati laŇĺnih vrednosti // medtem ko baza ni pisala. Ob vzpostavitvi omreŇĺja getBodyMetrics stream // samodejno prinese pravo vrednost iz Firestorea. val newStreak = completionResult?.newStreakDays?.takeIf { it > 0 } ?: _ui.value.streakDays val newPlanDay = completionResult?.newPlanDay?.takeIf { it > 0 } ?: (oldPlanDay + if (!isExtra) 1 else 0) val newWeekly = if (todayStatus != UserDayStatus.REST_WORKOUT_DONE) (oldWeeklyDone + 1).coerceAtMost(_ui.value.weeklyTarget) else oldWeeklyDone
_ui.value = _ui.value.copy( streakDays = newStreak, weeklyDone = newWeekly, planDay = newPlanDay, isWorkoutDoneToday = true, todayStatus = todayStatus, showCompletionAnimation = !isExtra, isLoading = false ) _streakUpdatedEvent.tryEmit(StreakUpdateEvent(newStreak = newStreak)) intent.onCompletion(completionResult) } result.onFailure { error -> _ui.value = _ui.value.copy(isLoading = false, errorMessage = error.message) intent.onCompletion(null) } } } } } }

package com.example.myapplication.viewmodels
import androidx.lifecycle.ViewModel import androidx.lifecycle.viewModelScope import com.example.myapplication.R import com.example.myapplication.data.UserProfile import com.example.myapplication.domain.model.BodyField import com.example.myapplication.domain.model.BodyGoldenRatioResult import com.example.myapplication.domain.model.PlanResult import com.example.myapplication.domain.model.UserDayStatus import com.example.myapplication.domain.gamification.ManageGamificationUseCase import com.example.myapplication.domain.gamification.WorkoutCompletionResult import com.example.myapplication.domain.auth.AuthStateRepository import com.example.myapplication.domain.profile.UserProfileRepository import com.example.myapplication.domain.model.BodyMeasurementEntry import com.example.myapplication.domain.repository.BodyMeasurementsRepository import com.example.myapplication.domain.usecase.CalculateBodyGoldenRatioUseCase import com.example.myapplication.domain.usecase.GetBodyMetricsUseCase import com.example.myapplication.domain.usecase.SaveBodyMeasurementsUseCase import com.example.myapplication.domain.usecase.SwapPlanDaysUseCase import com.example.myapplication.domain.usecase.UpdateBodyMetricsUseCase import com.example.myapplication.domain.usecase.ValidationResult import kotlinx.coroutines.CancellationException import kotlinx.coroutines.Job import kotlinx.coroutines.channels.Channel import kotlinx.coroutines.flow.MutableSharedFlow import kotlinx.coroutines.flow.MutableStateFlow import kotlinx.coroutines.flow.SharedFlow import kotlinx.coroutines.flow.SharingStarted import kotlinx.coroutines.flow.StateFlow import kotlinx.coroutines.flow.asSharedFlow import kotlinx.coroutines.flow.asStateFlow import kotlinx.coroutines.flow.combine import kotlinx.coroutines.flow.flatMapLatest import kotlinx.coroutines.flow.flowOf import kotlinx.coroutines.flow.receiveAsFlow import kotlinx.coroutines.flow.stateIn import kotlinx.coroutines.flow.update import kotlinx.coroutines.launch
/** * Faza 30.9 ‚ÄĒ Enkratni UI dogodki za BodyModul. * * Razlika od StateFlow: * StateFlow = trajno stanje (kateri zaslon je odprt, ali nalagamo‚Ä¶) * Channel = enkratni dogodek (prikaŇĺi Snackbar, navigiraj, zapri dialog) * * Ne smeŇ° shranjevati teh vrednosti v StateFlow ‚ÄĒ Snackbar bi se ob rotaciji zaslona * prikazal znova. Channel zagotavlja natanko en sprejem. */ sealed interface BodyUiEvent { /** Meritve so bile uspeŇ°no shranjene v Firestore. */ data object SaveSuccess : BodyUiEvent /** Napaka med shranjevanjem ‚ÄĒ prikaŇĺi Snackbar z [message]. */ data class Error(val message: String) : BodyUiEvent }
/** * Faza 31.1 ‚ÄĒ Enoten UI state za Golden Ratio sekcijo. * Faza 31.3 ‚ÄĒ inputErrorRes: Int? ‚Üí invalidFields: Set<BodyField> za per-field natanńćnost. * * Faza 31.6 ‚ÄĒ Dead code odstranjen: bodyProfile je zdaj private, measurementsHistory izbrisan. * * NadomeŇ°ńća tri razprŇ°ene StateFlow-e (zdaj odstranjene/private): * bodyProfile (private) ‚Üí pokrit z Loading/Success * goldenRatioResults: StateFlow<Result?> ‚Üí Success.data * isSaving: StateFlow<Boolean> ‚Üí Success.isSaving * * Prednosti: * ‚ÄĘ Atomarni prehodi ‚ÄĒ UI nikoli ne vidi nedosledne kombinacije vrednosti * ‚ÄĘ Loading stanje prepreńćuje vizualno utripanje ("flash of empty content") * ‚ÄĘ invalidFields: UI obarva SAMO polja, ki so dejansko zunaj meja */ sealed interface GoldenRatioUiState { /** Profil se nalaga iz Firestore ‚ÄĒ pokaŇĺi CircularProgressIndicator. */ data object Loading : GoldenRatioUiState
/** * Profil naloŇĺen ‚ÄĒ pokaŇĺi celotni vmesnik z vnosi. * @param profileHeight ViŇ°ina iz profila (za prikaz in izrańćun pas/viŇ°ina razmerja) * @param shoulderInput Faza 31.4 ‚ÄĒ surovi vnos za ramena (String, ne Double) * @param waistInput Faza 31.4 ‚ÄĒ surovi vnos za pas * @param hipInput Faza 31.4 ‚ÄĒ surovi vnos za boke (prazno = ni vnosu) * @param data Rezultat izrańćuna; null dokler vnos ni veljaven/popoln * @param isSaving true med Firestore batch write ‚ÄĒ gumb onemogońćen * @param invalidFields Set polj, ki so zunaj bioloŇ°kih meja (30‚Äď250 cm). * @param isInputComplete Faza 31.5 ‚ÄĒ true ko so vsa 4 polja (ramena, pas, boki, viŇ°ina) * uspeŇ°no parsana v vrednosti > 0.0. Ko false + data==null + ni napak, * UI prikaŇĺe nevtralen napotek za vnos. */ data class Success( val profileHeight: Double?, val shoulderInput: String = "", val waistInput: String = "", val hipInput: String = "", val data: BodyGoldenRatioResult?, val isSaving: Boolean = false, val invalidFields: Set<BodyField> = emptySet(), val isInputComplete: Boolean = false ) : GoldenRatioUiState
/** * Napaka pri inicializaciji zaslona (npr. izpad Firestore med nalaganjem profila). * NI namenjen validacijskim napakam vnosa ‚ÄĒ za to se uporablja [Success.invalidFields]. * @param messageRes ID string resursa (R.string.*) ‚ÄĒ lokalizabilen, brez Context v VM */ data class Error(val messageRes: Int) : GoldenRatioUiState }
/** * Faza 30.1 ‚ÄĒ Vhodni podatki za telesni Zlati Rez. * shoulderCm/waistCm = 0.0 pomeni: ni vnosa ‚Üí goldenRatioResults = null. */ data class BodyMeasurementsInput( val shoulderCm: Double = 0.0, val waistCm: Double = 0.0, val hipCm: Double = 0.0, val heightCm: Double = 0.0 // fallback, ńće profil nima viŇ°ine )
/** * Faza 31.4 ‚ÄĒ Surovi tekstovni vnosi za telesne mere. * Nahajajo se v ViewModel StateFlow (ne v lokalni Compose state!) ‚Üí * preŇĺivijo UI state tranzicije (Loading ‚Üí Success itd.) brez izgube. */ data class BodyMeasurementsInputText( val shoulder: String = "", val waist: String = "", val hip: String = "" )
data class Challenge( val id: String, val title: String, val description: String, val xpReward: Int = 100, val accepted: Boolean = false, val completed: Boolean = false, val iconRes: Int? = null )
/** * UI stanje za Body Home zaslon. * * Faza 21: todayStatus je zdaj tipsko-varni [UserDayStatus] namesto String. */ data class BodyHomeUiState( val streakDays: Int = 0, val streakFreezes: Int = 0, val weeklyDone: Int = 0, val weeklyTarget: Int = 3, val planDay: Int = 1, val totalWorkoutsCompleted: Int = 0, val workoutsToday: Int = 0, val isWorkoutDoneToday: Boolean = false, val dailyKcal: Int = 0, val showCompletionAnimation: Boolean = false, val todayIsRest: Boolean = false, val outdoorSuggestion: String? = null, val errorMessage: String? = null, val isLoading: Boolean = false, /** Faza 31.8 ‚ÄĒ true Ň°ele ko LoadMetrics uspeŇ°no konńća (Firestore vrne podatke). * false = privzete vrednosti (planDay=1 itd.) so Ň†E VEDNO nezanesljive. * Guard v CompleteWorkoutSession prepreńći Firestore transakcijo z napańćnim planDay. */ val isDataLoaded: Boolean = false, /** Tipsko-varni status danaŇ°njega dne ‚ÄĒ nadomeŇ°ńća String "WORKOUT_DONE" itd. */ val todayStatus: UserDayStatus = UserDayStatus.WORKOUT_PENDING, val challenges: List<Challenge> = listOf( Challenge("c1", "30 days sixpack", "Get a sixpack in 30 days. Perform core exercises daily.", 500), Challenge("c2", "30 days pushups", "Improve your pushups in 30 days. Do 50 pushups/day.", 300), Challenge("c3", "Mobility week", "Increase your ROM in 7 days. Stretch every morning.", 150) ) )
sealed class BodyHomeIntent { data class LoadMetrics(val email: String, val plan: PlanResult? = null) : BodyHomeIntent() object CompleteRestDay : BodyHomeIntent() object HideCompletionAnimation : BodyHomeIntent() data class AcceptChallenge(val id: String) : BodyHomeIntent() data class CompleteChallenge(val id: String) : BodyHomeIntent() data class SwapDays(val currentPlan: PlanResult, val dayA: Int, val dayB: Int, val onResult: (PlanResult) -> Unit) : BodyHomeIntent() data class CompleteWorkoutSession( val email: String, val isExtraWorkout: Boolean = false, val totalKcal: Int = 0, val totalTimeMin: Double = 0.0, val exerciseResults: List<Map<String, Any>> = emptyList(), val focusAreas: List<String> = emptyList(), val onCompletion: (WorkoutCompletionResult?) -> Unit = {} ) : BodyHomeIntent() }
data class StreakUpdateEvent(val newStreak: Int, val isRestDay: Boolean = false)
/** * Faza 30.2 ‚ÄĒ BodyModuleHomeViewModel brez kakrŇ°nih koli Firebase SDK klicev. * Faza 30.6 ‚ÄĒ Dodan BodyMeasurementsRepository za zgodovino meritev. * * Auth stanje pride reaktivno prek [AuthStateRepository] vmesnika. * Profil se avtomatińćno osveŇĺuje ob spremembi prijave (flatMapLatest). */ class BodyModuleHomeViewModel( private val getBodyMetrics: GetBodyMetricsUseCase, private val updateBodyMetrics: UpdateBodyMetricsUseCase, private val swapPlanDays: SwapPlanDaysUseCase, private val gamificationUseCase: ManageGamificationUseCase? = null, private val userProfileRepository: UserProfileRepository, private val authStateRepository: AuthStateRepository, // Faza 30.6: Repozitorij za shranjevanje in opazovanje zgodovine meritev private val bodyMeasurementsRepository: BodyMeasurementsRepository ) : ViewModel() {
// ‚ĒÄ‚ĒÄ Faza 30.1 ‚ÄĒ Domain Use Case za telesni Zlati Rez ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ private val calculateBodyGoldenRatio = CalculateBodyGoldenRatioUseCase()
// ‚ĒÄ‚ĒÄ Faza 30.6 ‚ÄĒ Use Case za shranjevanje meritev (DI prek konstruktorja) ‚ĒÄ‚ĒÄ private val saveMeasurementsUseCase = SaveBodyMeasurementsUseCase(bodyMeasurementsRepository)
// ‚ĒÄ‚ĒÄ Faza 30.2 ‚ÄĒ Reaktivni profil brez Firebase v VM ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ /** * flatMapLatest: ob vsaki spremembi stanja prijave (login/logout) se * avtomatińćno zamenja na pravi profil ali flowOf(null). * PreŇĺivi rotacijo zaslona ‚ÄĒ ViewModel ostane Ňĺiv med config change. * * Faza 31.6 ‚ÄĒ private: profil se ne izpostavlja UI neposredno. * Javni dostop poteka izkljuńćno prek goldenRatioUiState. */ private val bodyProfile: StateFlow<UserProfile?> = authStateRepository.observeCurrentUserEmail() .flatMapLatest { email -> if (email != null) userProfileRepository.observeUserProfile(email) else flowOf(null) } .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), null)
// ‚ĒÄ‚ĒÄ Faza 30.1 ‚Üí Faza 31.4 ‚ÄĒ Vhodni teksti (String, ne Double) v ViewModel ‚ĒÄ /** * Faza 31.4 ‚ÄĒ Surovi vnosi so StateFlow v ViewModel (ne lokalni rememberSaveable). * PreŇĺivijo vsak UI state transition (Loading ‚ÜĒ Success) brez izgube vrednosti. */ private val _inputText = MutableStateFlow(BodyMeasurementsInputText())
// ‚ĒÄ‚ĒÄ Faza 30.8 ‚ÄĒ Stanje shranjevanja (interno ‚ÄĒ javno prek goldenRatioUiState) ‚ĒÄ private val _isSaving = MutableStateFlow(false)
/** * Faza 31.1 ‚ÄĒ ENOTEN UI STATE za Golden Ratio sekcijo. * Faza 31.4 ‚ÄĒ Input strings so del Success stanja ‚Üí UI vidi tońćno kar je vtipkal. * * Kombinira 3 vire (bodyProfile + _inputText + _isSaving) v en atomaren tok. * Parsing string‚ÜíDouble se dogaja TUKAJ ‚ÄĒ UI ostane ńćist (ne operira s float-i). */ val goldenRatioUiState: StateFlow<GoldenRatioUiState> = combine( bodyProfile, _inputText, _isSaving ) { profile, texts, saving -> // Faza 31.5 ‚ÄĒ Locale-safe parsing: zamenjaj vejico s piko (slovenska tipkovnica) // "75,5" ‚Üí "75.5" ‚Üí 75.5 | "" ‚Üí 0.0 | "abc" ‚Üí 0.0 val shoulderCm = texts.shoulder.replace(',', '.').toDoubleOrNull() ?: 0.0 val waistCm = texts.waist.replace(',', '.').toDoubleOrNull() ?: 0.0 val hipCm = texts.hip.replace(',', '.').toDoubleOrNull() ?: 0.0 val heightCm = profile?.height ?: 0.0
// Faza 31.5 ‚ÄĒ Zastavica za POPOLN vnos: vsa 4 polja > 0 // false ‚Üí UI prikaŇĺe nevtralen napotek; true + data!=null ‚Üí prikaŇĺi rezultat val isInputComplete = shoulderCm > 0.0 && waistCm > 0.0 && hipCm > 0.0 && heightCm > 0.0
when { profile == null -> GoldenRatioUiState.Loading else -> { // Klińći UseCase samo ko sta obe obvezni vrednosti vneseni if (shoulderCm > 0.0 && waistCm > 0.0) { when (val validation = calculateBodyGoldenRatio( shoulderCm = shoulderCm, waistCm = waistCm, hipCm = hipCm, heightCm = heightCm, isMale = profile.gender?.equals("Male", ignoreCase = true) ?: true )) { is ValidationResult.Success -> GoldenRatioUiState.Success( profileHeight = profile.height, shoulderInput = texts.shoulder, waistInput = texts.waist, hipInput = texts.hip, data = validation.data, isSaving = saving, invalidFields = emptySet(), isInputComplete = isInputComplete ) is ValidationResult.Invalid -> { android.util.Log.d( "BodyModuleHomeVM", "Per-field napaka: ${validation.invalidFields}" ) GoldenRatioUiState.Success( profileHeight = profile.height, shoulderInput = texts.shoulder, waistInput = texts.waist, hipInput = texts.hip, data = null, isSaving = saving, invalidFields = validation.invalidFields, isInputComplete = isInputComplete ) } } } else { // Polja prazna ali nepopolna ‚ÄĒ ńćisto stanje GoldenRatioUiState.Success( profileHeight = profile.height, shoulderInput = texts.shoulder, waistInput = texts.waist, hipInput = texts.hip, data = null, isSaving = saving, invalidFields = emptySet(), isInputComplete = isInputComplete ) } } } }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), GoldenRatioUiState.Loading)
/** * Faza 31.4 ‚ÄĒ Posodobi surove vnosne tekste (iz UI TextField). * Parsing string‚ÜíDouble se izvaja v combine, ne tukaj. */ fun updateInputText(shoulder: String, waist: String, hip: String) { _inputText.value = BodyMeasurementsInputText(shoulder, waist, hip) }
/** Faza 30.1 klińće UI ko vnese meritve ‚ÄĒ obdrŇĺano za morebitne klice od drugod. */ fun updateBodyMeasurements( shoulderCm: Double, waistCm: Double, hipCm: Double = 0.0, heightCm: Double = 0.0 ) { // Delegiraj na updateInputText ‚ÄĒ pretvori nazaj v string za konsistentnost _inputText.value = BodyMeasurementsInputText( shoulder = if (shoulderCm > 0) shoulderCm.toString() else "", waist = if (waistCm > 0) waistCm.toString() else "", hip = if (hipCm > 0) hipCm.toString() else "" ) }
// ‚ĒÄ‚ĒÄ Faza 30.9 ‚ÄĒ Enkratni UI dogodki (Channel = natanko en sprejem) ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ /** * Channel<BodyUiEvent>: poŇ°iljamo enkratne dogodke (Snackbar, navigacija‚Ä¶). * receiveAsFlow() v UI posluŇ°a z LaunchedEffect. * * Zakaj Channel in ne SharedFlow: * SharedFlow (replay=0) bi izgubil dogodek, ńće UI ni Ň°e narońćen. * Channel.BUFFERED ohrani sporońćilo dokler ga UI ne prebere. */ private val _uiEvent = Channel<BodyUiEvent>(Channel.BUFFERED) val uiEvents = _uiEvent.receiveAsFlow()
/** * Faza 30.6 ‚ÄĒ Shrani meritve v Firestore (batch write): * a) Posodobi profil z aktualnimi vrednostmi * b) Doda vnos v measurements_history (za grafe) * * Faza 30.8 ‚ÄĒ isSaving guard: klik na gumb med shranjevanjem se v celoti ignorira. * Faza 30.9 ‚ÄĒ napake se poŇ°ljejo kot BodyUiEvent.Error na Channel (‚Üí Snackbar v UI). * * Klic chain: UI ‚Üí VM ‚Üí SaveBodyMeasurementsUseCase ‚Üí BodyMeasurementsRepository ‚Üí Firestore */ fun saveBodyMeasurements( shoulderCm: Double, waistCm: Double, hipCm: Double = 0.0, heightCm: Double = 0.0 ) { // Dvojni klik ‚Üí prezri, ńće shranjevanje Ňĺe teńće if (_isSaving.value) return viewModelScope.launch { _isSaving.value = true try { val result = saveMeasurementsUseCase(shoulderCm, waistCm, hipCm, heightCm) result.onSuccess { android.util.Log.d("BodyModuleHomeVM", "‚úÖ Meritve shranjene v zgodovino") _uiEvent.send(BodyUiEvent.SaveSuccess) } result.onFailure { e -> android.util.Log.e("BodyModuleHomeVM", "‚ĚĆ Napaka pri shranjevanju meritev: ${e.message}") _uiEvent.send(BodyUiEvent.Error("Shranjevanje ni uspelo. Preverite povezavo.")) } } finally { // Vedno osvobodi, tudi ob nenapovedani izjemi _isSaving.value = false } } }
// ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ‚ĒÄ
private val _ui = MutableStateFlow(BodyHomeUiState()) val ui: StateFlow<BodyHomeUiState> = _ui.asStateFlow()
private val _streakUpdatedEvent = MutableSharedFlow<StreakUpdateEvent>(extraBufferCapacity = 1) val streakUpdatedEvent: SharedFlow<StreakUpdateEvent> = _streakUpdatedEvent.asSharedFlow()
/** * Faza 23: Job tracking za LoadMetrics ‚ÄĒ vsak klic cancela prejŇ°njega. * Prepreńćuje race condition med vzporednimi Firestore branii. */ private var loadMetricsJob: Job? = null
fun handleIntent(intent: BodyHomeIntent) { when (intent) { is BodyHomeIntent.LoadMetrics -> { // Cancela morebitni prejŇ°nji LoadMetrics ‚ÄĒ prepreńći dvojno branje loadMetricsJob?.cancel() loadMetricsJob = viewModelScope.launch { _ui.value = _ui.value.copy(isLoading = true, errorMessage = null) try { getBodyMetrics.invoke(intent.email).collect { metrics -> if (metrics.isLoading) return@collect val todayIsRest = intent.plan?.weeks ?.flatMap { it.days } ?.firstOrNull { it.dayNumber == metrics.planDay } ?.isRestDay ?: false
_ui.value = _ui.value.copy( streakDays = metrics.streakDays, streakFreezes = metrics.streakFreezes, weeklyDone = metrics.weeklyDone, weeklyTarget = metrics.weeklyTarget, planDay = metrics.planDay, totalWorkoutsCompleted = metrics.totalWorkoutsCompleted, isWorkoutDoneToday = metrics.isWorkoutDoneToday, dailyKcal = metrics.dailyKcal, todayIsRest = todayIsRest, todayStatus = metrics.todayStatus, isLoading = false, isDataLoaded = true, errorMessage = metrics.errorMessage ) } } catch (e: CancellationException) { // Faza 31.8 ‚ÄĒ Anomalija 1: Preklicani stari job ne sme mutirati stanja novega joba. // Re-throwamo, da isLoading = true (ki ga je postavil novi job) ostane nespremenjen. throw e } catch (e: Exception) { _ui.value = _ui.value.copy(errorMessage = e.message, isLoading = false) } } }
is BodyHomeIntent.CompleteRestDay -> { if (gamificationUseCase == null) { android.util.Log.w("BodyModuleHomeVM", "gamificationUseCase ni nastavljen ‚ÄĒ preskońćim CompleteRestDay") return } viewModelScope.launch { _ui.value = _ui.value.copy(isLoading = true) try { val newStreak = gamificationUseCase.restDayInitiated() _ui.value = _ui.value.copy( isWorkoutDoneToday = true, streakDays = newStreak, todayStatus = UserDayStatus.REST_DAY_DONE, isLoading = false ) _streakUpdatedEvent.tryEmit(StreakUpdateEvent(newStreak = newStreak, isRestDay = true)) } catch (e: Exception) { _ui.value = _ui.value.copy(isLoading = false, errorMessage = e.message) } } }
is BodyHomeIntent.HideCompletionAnimation -> _ui.value = _ui.value.copy(showCompletionAnimation = false)
is BodyHomeIntent.AcceptChallenge -> { /* lokalni state */ } is BodyHomeIntent.CompleteChallenge -> { /* lokalni state */ }
is BodyHomeIntent.SwapDays -> { // Faza 30.4: ViewModel klińće SAMO SwapPlanDaysUseCase ‚ÄĒ ne PlanDataStore. // Klic chain: VM ‚Üí UseCase (validacija + lokalni model) ‚Üí Repository ‚Üí DataStore viewModelScope.launch { // Faza 31.8 ‚ÄĒ Anomalija 3: Snapshot pred pisanjem in pred suspend klicem. // lockedDay preberemo iz nespremenljivega snapshot-a, ne iz Ňĺivega _ui.value. val swapSnapshot = _ui.value _ui.value = swapSnapshot.copy(isLoading = true, errorMessage = null) val lockedDay = if (swapSnapshot.isWorkoutDoneToday) swapSnapshot.planDay else null val res = swapPlanDays.invoke(intent.currentPlan, intent.dayA, intent.dayB, lockedDay) // Faza 31.8 ‚ÄĒ Anomalija 2: Atomarni zapis ‚ÄĒ isLoading in errorMessage v enem klicu. // UI ne vidi vmesnega stanja {isLoading=false, errorMessage=null} ko dejansko obstaja napaka. _ui.update { it.copy(isLoading = false, errorMessage = res.exceptionOrNull()?.message) } res.onSuccess { updatedPlan -> // Use case vrne posodobljeni model Ň°ele po uspeŇ°ni Firestore transakciji intent.onResult(updatedPlan) } } }
is BodyHomeIntent.CompleteWorkoutSession -> { viewModelScope.launch { // Faza 31.8 ‚ÄĒ Anomalija 3: Nespremenljiv snapshot PRED vsemi pisanji in suspend klici. // Vsi nadaljnji izrańćuni (oldPlanDay, newStreak, newWeekly) temeljijo izkljuńćno // na tem snapshot-u, ne na Ňĺivem _ui.value, ki ga medtem dapat spremeniti druga korutina. val currentStateSnapshot = _ui.value _ui.value = currentStateSnapshot.copy(isLoading = true, errorMessage = null)
// Faza 31.8 ‚ÄĒ Anomalija 5: Guard pred Firestore transakcijo. // Prepreńći poŇ°iljanje privzetega planDay=1 v updateBodyMetrics, ńće LoadMetrics // Ň°e ni uspeŇ°no zakljuńćil (Firestore napaka, offline, hiter tap ob zagonu). if (!currentStateSnapshot.isDataLoaded) { _ui.update { it.copy(isLoading = false, errorMessage = "Metrics not yet loaded ‚ÄĒ please wait.") } intent.onCompletion(null) return@launch }
val isRestDay = currentStateSnapshot.todayIsRest val isExtra = intent.isExtraWorkout val oldPlanDay = currentStateSnapshot.planDay val oldWeeklyDone = currentStateSnapshot.weeklyDone
val result = updateBodyMetrics.invoke( email = intent.email, totalKcal = intent.totalKcal, totalTimeMin = intent.totalTimeMin, exercisesCount = intent.exerciseResults.size, planDay = oldPlanDay, isExtra = isExtra, exerciseResults = intent.exerciseResults, focusAreas = intent.focusAreas, isRestDay = isRestDay )
result.onSuccess { completionResult -> // Faza 23: Optimistińćni update iz WorkoutCompletionResult ‚ÄĒ brez dodatnega Firestore read-a. // moveToNextDay() je atomarno Ňĺe zapisal vse podatke; streak + planDay sta znana. val todayStatus = when { isRestDay && isExtra -> UserDayStatus.REST_WORKOUT_DONE else -> UserDayStatus.WORKOUT_DONE } // Faza 31.8 ‚ÄĒ Anomalija 4: Fallback vrednosti beremo iz currentStateSnapshot, // ne iz Ňĺivega _ui.value ‚ÄĒ _ui.value se je med suspend klicem (updateBodyMetrics) // morda spremenil (npr. vzporedni CompleteRestDay). // Faza 31.6 avdit: moveToNextDay() vrne -1 ob Firestore napaki in 0 ob // de-dup preskoku. Oba primera zafiltrirana z takeIf { it > 0 }. val newStreak = completionResult?.newStreakDays?.takeIf { it > 0 } ?: currentStateSnapshot.streakDays val newPlanDay = completionResult?.newPlanDay?.takeIf { it > 0 } ?: (oldPlanDay + if (!isExtra) 1 else 0) val newWeekly = if (todayStatus != UserDayStatus.REST_WORKOUT_DONE) (oldWeeklyDone + 1).coerceAtMost(currentStateSnapshot.weeklyTarget) else oldWeeklyDone
_ui.value = _ui.value.copy( streakDays = newStreak, weeklyDone = newWeekly, planDay = newPlanDay, isWorkoutDoneToday = true, todayStatus = todayStatus, showCompletionAnimation = !isExtra, isLoading = false ) _streakUpdatedEvent.tryEmit(StreakUpdateEvent(newStreak = newStreak)) intent.onCompletion(completionResult) } result.onFailure { error -> _ui.value = _ui.value.copy(isLoading = false, errorMessage = error.message) intent.onCompletion(null) } } } } } }
